import React from 'react'
import { useTranslation } from 'react-i18next'
import { DialogOverlay, DialogOverlayActions, DialogOverlayFooter, Button } from '@fs/zion-ui'
import { stopHelping } from './utils'

export default function ConfirmationDialog({ overlay, redirectAfterStopUrl }) {
  const { t } = useTranslation()
  return (
    <DialogOverlay title={t('stop_helping_heading', 'Stop Helping Others')} {...overlay}>
      {t('are_you_sure_stop', 'Are you sure you would like to stop helping others?')}

      <DialogOverlayFooter>
        <DialogOverlayActions>
          <Button onClick={() => stopHelping(redirectAfterStopUrl)}>{t('stopButton', 'Stop')}</Button>
        </DialogOverlayActions>
      </DialogOverlayFooter>
    </DialogOverlay>
  )
}
